const AutomatedReasoningPolicyScenario = @import("automated_reasoning_policy_scenario.zig").AutomatedReasoningPolicyScenario;

/// Contains a comprehensive entity encompassing all the scenarios generated by
/// the build workflow, which can be used to validate an Automated Reasoning
/// policy.
pub const AutomatedReasoningPolicyScenarios = struct {
    /// Represents a collection of generated policy scenarios.
    policy_scenarios: []const AutomatedReasoningPolicyScenario,

    pub const json_field_names = .{
        .policy_scenarios = "policyScenarios",
    };
};
